                return
            }

            self.isDone[atIndex] = true
            self.numberOfDone += 1

            if self.numberOfDone == self.parent.count {
                self.forwardOn(.completed)
                self.dispose()
            }
            else {
                self.subscriptions[atIndex].dispose()
            }
